import React, { useState, useEffect } from 'react';
import { Box, Heading, Button, Flex, Table, Tbody, Td, Th, Thead, Tr, useToast, Spinner } from '@chakra-ui/react';
import axios from 'axios';
import moment from 'moment';

const AdminDashboard = () => {
  const [view, setView] = useState('realTime'); // 'realTime' or 'browseAndDownload'
  const [currentTasks, setCurrentTasks] = useState([]);
  const [loading, setLoading] = useState(false);
  const [idleTimes, setIdleTimes] = useState({}); // Store idle times per user
  const toast = useToast();

  useEffect(() => {
    let intervalId;

    if (view === 'realTime') {
      fetchCurrentTasks();
      intervalId = setInterval(fetchCurrentTasks, 5000); // Refresh every 5 seconds
    }

    return () => {
      if (intervalId) clearInterval(intervalId);
    };
  }, [view]);

  // Fetch Current Tasks for Real-Time Monitoring
  const fetchCurrentTasks = async () => {
    setLoading(true);
    try {
      const response = await axios.get('http://localhost:5000/api/tasks/current-tasks', {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
        },
      });

      const tasksData = response.data;

      // Set the last idle start time for each user if they become idle
      const updatedIdleTimes = { ...idleTimes };

      tasksData.forEach(({ user, activeTask }) => {
        if (!activeTask && !updatedIdleTimes[user.email]) {
          updatedIdleTimes[user.email] = Date.now(); // User becomes idle, set start time
        } else if (activeTask) {
          delete updatedIdleTimes[user.email]; // User is active, remove idle start time
        }
      });

      setIdleTimes(updatedIdleTimes);
      setCurrentTasks(tasksData);
    } catch (error) {
      console.error('Error fetching current tasks:', error);
      toast({
        title: 'Error',
        description: 'Failed to fetch tasks. Please try again.',
        status: 'error',
        duration: 3000,
        isClosable: true,
      });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const idleInterval = setInterval(() => {
      setIdleTimes((prevIdleTimes) => {
        const newIdleTimes = { ...prevIdleTimes };
        Object.keys(newIdleTimes).forEach((userEmail) => {
          newIdleTimes[userEmail] = newIdleTimes[userEmail]; // Just trigger a re-render
        });
        return newIdleTimes;
      });
    }, 1000); // Update idle times every second

    return () => clearInterval(idleInterval);
  }, []);

  return (
    <Box maxW="80%" mx="auto" mt={10} p={5} borderWidth={1} borderRadius="lg">
      <Heading as="h3" size="lg" mb={6} textAlign="center">
        Admin Dashboard
      </Heading>

      {/* Panel for Selecting View */}
      <Flex justifyContent="center" mb={6}>
        <Button colorScheme="teal" mr={4} onClick={() => setView('realTime')}>
          Real-Time Data
        </Button>
      </Flex>

      {/* Real-Time Data View */}
      {view === 'realTime' && (
        <Box>
          <Heading as="h4" size="md" mb={4}>
            Current Status of Team Members
          </Heading>
          {loading ? (
            <Spinner size="lg" />
          ) : (
            <Table variant="striped" colorScheme="teal">
              <Thead>
                <Tr>
                  <Th>Team Member</Th>
                  <Th>Status</Th>
                  <Th>Task ID</Th>
                  <Th>Queue</Th>
                  <Th>Time Spent (so far)</Th>
                  <Th>Idle Time</Th>
                </Tr>
              </Thead>
              <Tbody>
                {currentTasks.map(({ user, activeTask }) => {
                  // Calculate time spent
                  const timeSpent =
                    activeTask
                      ? moment
                          .duration(moment().diff(moment(activeTask.createdAt), 'milliseconds'))
                          .humanize()
                      : 'N/A';

                  // Calculate idle time
                  const idleStartTime = idleTimes[user.email];
                  const idleDuration =
                    !activeTask && idleStartTime
                      ? moment.duration(moment().diff(idleStartTime)).humanize()
                      : '-';

                  return (
                    <Tr key={user.email}>
                      <Td>{`${user.firstName} ${user.lastName}`}</Td>
                      <Td>{activeTask ? 'Active' : 'Idle'}</Td>
                      <Td>{activeTask ? activeTask.taskId : '-'}</Td>
                      <Td>{activeTask ? activeTask.queue : '-'}</Td>
                      <Td>{activeTask ? timeSpent : '-'}</Td>
                      <Td>{!activeTask ? idleDuration : '-'}</Td>
                    </Tr>
                  );
                })}
              </Tbody>
            </Table>
          )}
        </Box>
      )}
    </Box>
  );
};

export default AdminDashboard;
